/**
 * @param other The other point
 * @return the distance between this point and the other vector.
 */
public float dst(GridPoint2Mutant other) {
    int xd = other.x - x;
    int yd = other.y - y;
    return (float) Math.sqrt(xd * xd + yd * yd);
}
